// Task representa o modelo de tarefa
type Task struct {
	ID          string    `json:"id"`
	Title       string    `json:"title"`
	Description string    `json:"description"`
	Done        bool      `json:"done"`
	CreatedAt   time.Time `json:"created_at"`
}

var (
	tasks = make(map[string]Task)
	mu    sync.Mutex
	nextID int = 1
)

func main() {
	router := mux.NewRouter()

	router.HandleFunc("/api/tasks", getTasks).Methods("GET")
	router.HandleFunc("/api/tasks", createTask).Methods("POST")
	router.HandleFunc("/api/tasks/{id}", getTask).Methods("GET")
	router.HandleFunc("/api/tasks/{id}", updateTask).Methods("PUT")
	router.HandleFunc("/api/tasks/{id}", deleteTask).Methods("DELETE")

	fmt.Println("Server listening on port 8080...")
	log.Fatal(http.ListenAndServe(":8080", router))
}

// getTasks retorna todas as tarefas
func getTasks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	mu.Lock()
	defer mu.Unlock()

	// Convert map to slice for JSON encoding
	var allTasks []Task
	for _, task := range tasks {
		allTasks = append(allTasks, task)
	}

	json.NewEncoder(w).Encode(allTasks)
}

// createTask cria uma nova tarefa
func createTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	var task Task
	_ = json.NewDecoder(r.Body).Decode(&task)

	mu.Lock()
	defer mu.Unlock()

	task.ID = strconv.Itoa(nextID)
	nextID++
	task.CreatedAt = time.Now()
	tasks[task.ID] = task

	json.NewEncoder(w).Encode(task)
}

// getTask busca uma tarefa por ID
func getTask(w http.ResponseWriter, r *http.ResponseWriter) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	mu.Lock()
	defer mu.Unlock()

	task, ok := tasks[params["id"]]
	if !ok {
		http.Error(w, "Task not found", http.StatusNotFound)
		return
	}
	json.NewEncoder(w).Encode(task)
}

// updateTask atualiza uma tarefa existente
func updateTask(w http.ResponseWriter, r *http.ResponseWriter) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	mu.Lock()
	defer mu.Unlock()

	_, ok := tasks[params["id"]]
	if !ok {
		http.Error(w, "Task not found", http.StatusNotFound)
		return
	}

	var updatedTask Task
	_ = json.NewDecoder(r.Body).Decode(&updatedTask)
	updatedTask.ID = params["id"] // Ensure ID remains the same
	tasks[params["id"]] = updatedTask

	json.NewEncoder(w).Encode(updatedTask)
}

// deleteTask remove uma tarefa
func deleteTask(w http.ResponseWriter, r *http.ResponseWriter) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	mu.Lock()
	defer mu.Unlock()

	_, ok := tasks[params["id"]]
	if !ok {
		http.Error(w, "Task not found", http.StatusNotFound)
		return
	}

	delete(tasks, params["id"])
	w.WriteHeader(http.StatusNoContent)
}
"}

