		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	mu.Lock()
	defer mu.Unlock()

	task.ID = strconv.Itoa(nextID)
	nextID++
	task.CreatedAt = time.Now()
	tasks[task.ID] = task

	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(task)
}

