import shutil

def organize_files(source_dir):
    text_dir = os.path.join(source_dir, 'textos')
    json_dir = os.path.join(source_dir, 'dados')

    os.makedirs(text_dir, exist_ok=True)
    os.makedirs(json_dir, exist_ok=True)

    for filename in os.listdir(source_dir):
        if os.path.isfile(os.path.join(source_dir, filename)):
            if filename.endswith('.txt'):
                shutil.move(os.path.join(source_dir, filename), os.path.join(text_dir, filename))
                print(f"Movido {filename} para {text_dir}")
            elif filename.endswith('.json'):
                shutil.move(os.path.join(source_dir, filename), os.path.join(json_dir, filename))
                print(f"Movido {filename} para {json_dir}")

if __name__ == '__main__':
    # Usa o diretório atual como diretório de origem
    current_directory = os.getcwd()
    organize_files(current_directory)
